VALUES
  ('social-worker-moex-06040', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「夫尺有所短，寸有所長，物有所不足，智有所不明。」（《楚辭．卜居》）意思 是：', '["萬物都有其擅長與局限之處", "心胸狹隘者看人、看事都只見到缺點", "尺、寸長短不同，要用在適合之處才能發揮功能", "尺是較短的量器，測量時不足以測量出全貌；寸是較長的量器，智者有時不知加 以利用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06041', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '孔子曾說：「人之過也，各於其黨。觀過，斯知仁矣！」（《論語．里仁》）運用 三段式推理，此段文意應為下列那一選項？', '["什麼類別的人就會犯什麼類別的過失（大前提） 只要觀察他是什麼類別的人（小前提） 就可以推知他會犯什麼過失（結論）", "什麼類別的人就會犯什麼類別的過失（大前提） 只要觀察他所犯的過失（小前提） 就可以推知他是什麼類別的人（結論）", "犯什麼類別的過失就會是什麼類別的人（大前提） 只要觀察他所犯的過失（小前提） 就可以推知他是什麼類別的人（結論）", "犯什麼類別的過失就會是什麼類別的人（大前提） 只要觀察他是什麼類別的人（小前提） 就可以推知他會犯什麼過失（結論）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06042', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '醫扁鵲見秦武王，武王示之病，扁鵲請除。左右曰：「君之病，在耳之前，目之下， 除之未必已也，將使耳不聰，目不明。」君以告扁鵲。扁鵲怒而投其石，曰： 「君與知之者謀之，而與不知者敗之。使此知秦國之政也，則君一舉而亡國矣！」 （《戰國策．秦策二》）上述這段文字的主旨，下列選項何者錯誤？', '["疑人不用，用人不疑", "用人不專，必然敗事", "廣納諫言，三思而行", "信任專業，與知者謀"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06043', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '《禮記．學記》：「大學之法，禁於未發之謂豫，當其可之謂時，不陵節而施之謂孫， 相觀而善之謂摩。此四者，教之所由興也。」根據上文所述，大學教育興盛之原因， 具備那四種原則？', '["思慮、適可、謙遜、讚美", "禁止、適當、實施、觀察", "預備、時間、禮節、善良", "預防、及時、循序、觀摩"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06044', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '李白〈與韓荊州書〉：「白隴西布衣，流落楚漢，十五好劍術，徧干諸侯，三十成 文章，歷抵卿相，雖長不滿七尺，而心雄萬夫，王公大臣，許與氣義，此疇曩心跡， 安敢不盡於君侯哉？君侯制作侔神明，德行動天地，筆參造化，學究天人，幸願開 張心顏，不以長揖見拒，必若接之以高宴，縱之以清談，請日試萬言，倚馬可待。 今天下以君侯為文章之司命，人物之權衡，一經品題，便作佳士，而君侯何惜階前 盈尺之地，不使白揚眉吐氣，激昂青雲耶？」 根據上文，下列敘述何者正確？', '["李白羨慕平步青雲之人", "李白希望君侯賞識他的才華", "李白在君侯面前吐露心中的委屈", "李白希望透過君侯之助成為文壇盟主"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06045', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '客有歌於郢中者，其始曰《下里巴人》，國中屬而和者數千人；其為《陽阿薤露》， 國中屬而和者數百人；其為《陽春白雪》，國中屬而和者數十人而已也；引商刻角， 雜以流徵，國中屬而和者不過數人。是其曲彌高者，其和彌寡。 以上故事的寓意，與下列選項敘述何者意義相近？', '["小眾文化常是叫座不叫好", "主流文化反而是比較優秀", "高深優秀的作品能欣賞的人不多", "真正優秀的作品是可以叫好又叫座的"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06046', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列那一個選項所表達的寓意，和其他三個選項不同？', '["為了保護劍刃的鋒利，劍鞘甘於駑鈍", "黑夜暗中幫助花朵綻放，卻將功勞讓予白日", "雲霧恰似大地的欲望，遮蔽了她所呼喊的太陽", "雲朵穿著華麗的彩裝，太陽卻只有一襲樸素的光袍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06047', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「如果你將一切錯誤關在門外，那真理也將被拒於門外。」下列那一個選項最能適 切地表達這句話的主旨？', '["積極把握每一個機會，正面迎擊", "勇敢面對每一次挫敗，才能迎接成功", "錯誤和真理同在，不能強加切割", "可以從錯誤中學習，而獲知真理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06048', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「如果你因為錯失太陽而流淚，那麼你也將錯失繁星。」下列那一個選項最能適切 地表達這句話的主旨？', '["把握當下，切勿沉湎於懊惱惋嘆", "善加觀察把握，切勿時常錯失良機", "錯失良機乃人情之常，不必懊惱惋嘆", "一步錯，步步錯。要謹慎踏出第一步"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06049', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '陳幸蕙〈黎明心情〉：「攤開的早報版面，常安靜地裸裎著這個世界的隱憂、人間 的荒誕。……偶有一些中性或明朗有趣的訊息，明滅閃爍其間，彷如黑咖啡裏撒下 的晶白糖屑，但調和了苦澀，增加了一小撮立即的甜郁之感之後，旋也湮沒不見。」 下列選項，何者並非作者之意？', '["安靜裸裎暗喻文字的明白揭露", "晶白糖屑是指令人欣喜的新聞", "明滅閃爍是指晶白糖屑的易融", "苦澀黑咖啡暗喻了世間的混亂"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
